lines = raw_data.strip().split('\n')
objects_to_create = []

print("Iniciando processamento dos dados...")

for line in lines:
    # Separa por tabulação
    parts = line.split('\t')
    
    # Remove espaços em branco extras das pontas
    parts = [p.strip() for p in parts]
    
    # Verificação para garantir que a linha tenha o número esperado de colunas
    if len(parts) != 16:
        print(f"Linha ignorada (número de colunas inesperado: {len(parts)}): {line[:50]}...")
        continue

    try:
        # Converte a data de DD/MM/YYYY para o formato do Django
        date_obj = datetime.strptime(parts[0], '%d/%m/%Y').date()
        
        obj = RegistroFinanceiro(
            data=date_obj,
            mes=parts[1],
            periodo=parts[2],
            arquivo=parts[3],
            rf_sub=parts[4],
            unidade_coordenacao=parts[5],
            grupos=parts[6],
            despesa_gerencial=parts[7],
            iniciativa=parts[8],
            gnd=parts[9],
            tipo_despesa=parts[10],
            ro_1=parse_currency(parts[11]),
            lme_1=parse_currency(parts[12]),
            po=parts[13],
            acao=parts[14],
            po_gnd=parts[15]
        )
        objects_to_create.append(obj)
    except ValueError as e:
        print(f"Erro ao converter data na linha: {line[:50]}... Erro: {e}")

# Inserção em massa (mais rápido)
if objects_to_create:
    RegistroFinanceiro.objects.bulk_create(objects_to_create)
    print(f"Sucesso! {len(objects_to_create)} registros foram inseridos no banco de dados.")
else:
    print("Nenhum registro encontrado para inserir.")